The task is to write a complete TypeScript program for Node.js that takes a DAG with tasks and dependency edges, and outputs a deterministic build order. The build order must be lexicographically smallest when multiple tasks are available, and must handle cycles by outputting "IMPOSSIBLE".

The algorithm to implement is Kahn's algorithm with a priority queue. Kahn's algorithm works as follows:
1. Calculate the in-degree of each task.
2. Put all tasks with in-degree 0 into a min-heap (priority queue).
3. While the heap is not empty:
   a. Extract the lexicographically smallest task.
   b. Add it to the result.
   c. For each task that this task depends on (outgoing edges), decrease its in-degree.
   d. If a task's in-degree becomes 0, add it to the heap.
4. If the result has N tasks, output them. Otherwise, there's a cycle, so output "IMPOSSIBLE".

The input format is:
- First line: N M
- Second line: N distinct task names
- Next M lines: A B meaning A must be completed before B

We need to read stdin using `fs.readFileSync(0, "utf8")`.

We need to implement a binary heap or another efficient priority queue. Since the input size can be up to N tasks, and we need O((N + M) log N) or better, a binary heap is suitable.

Let's write the code:

```typescript
import * as fs from "fs";

// Binary heap implementation for min-heap
class MinHeap<T> {
  private heap: T[];

  constructor() {
    this.heap = [];
  }

  push(item: T) {
    this.heap.push(item);
    this.bubbleUp(this.heap.length - 1);
  }

  pop() {
    if (this.heap.length === 0) {
      throw new Error("Empty heap");
    }
    if (this.heap.length === 1) {
      return this.heap.pop()!;
    }
    const min = this.heap[0];
    this.heap[0] = this.heap.pop()!;
    this.bubbleDown(0);
    return min;
  }

  private bubbleUp(index: number) {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[index] >= this.heap[parentIndex]) {
        break;
      }
      [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
      index = parentIndex;
    }
  }

  private bubbleDown(index: number) {
    const length = this.heap.length;
    while (true) {
      let leftIndex = 2 * index + 1;
      let rightIndex = 2 * index + 2;
      let smallest = index;
      if (leftIndex < length && this.heap[leftIndex] < this.heap[smallest]) {
        smallest = leftIndex;
      }
      if (rightIndex < length && this.heap[rightIndex] < this.heap[smallest]) {
        smallest = rightIndex;
      }
      if (smallest === index) {
        break;
      }
      [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
      index = smallest;
    }
  }
}

function main() {
  const data = fs.readFileSync(0, "utf8");
  const lines = data.trim().split("\n");

  const [N, M] = lines[0].split(" ").map(Number);
  const tasks = lines[1].split(" ");

  // Task name to index mapping
  const taskToIndex = new Map(tasks.map((task, index) => [task, index]));

  // In-degree of each task
  const inDegree = new Array(N).fill(0);

  // Adjacency list for the graph (outgoing edges)
  const adj = new Array(N).fill(null).map(() => []);

  // Parse M edges
  for (let i = 2; i < lines.length; i++) {
    const parts = lines[i].split(" ");
    if (parts.length !== 2) {
      continue;
    }
    const [A, B] = parts;
    const from = taskToIndex.get(A);
    const to = taskToIndex.get(B);
    if (from === null || to === null) {
      continue;
    }
    adj[from].push(to);
    inDegree[to]++;
  }

  // Priority queue for tasks with in-degree 0
  const pq = new MinHeap<string>();

  for (let i = 0; i < N; i++) {
    if (inDegree[i] === 0) {
      pq.push(tasks[i]);
    }
  }

  const result: string[] = [];

  while (pq.size > 0) {
    const task = pq.pop()!;
    result.push(task);
    const fromIndex = taskToIndex.get(task);
    if (fromIndex === null) {
      continue;
    }
    for (const toIndex of adj[fromIndex]) {
      inDegree[toIndex]--;
      if (inDegree[toIndex] === 0) {
        const toTask = tasks[toIndex];
        pq.push(toTask);
      }
    }
  }

  if (result.length < N) {
    console.log("IMPOSSIBLE");
  } else {
    console.log(result.join(" "));
  }
}

// @ts-ignore
MinHeap.prototype.size = function() {
  return this.heap.length;
};

main();
```

